select

from t_live_time_duration_config

    is_deleted = 0

        and id = #{id}


        and status = #{status}


        and duration_name like concat('%', #{durationName}, '%')


        and duration_value = #{durationValue}



    order by ${orderBy}


    order by duration_sort asc, duration_value asc


    limit #{pageNo}, #{pageSize}

select count(1)
from t_live_time_duration_config

    is_deleted = 0

        and id = #{id}


        and status = #{status}


        and duration_name like concat('%', #{durationName}, '%')


        and duration_value = #{durationValue}
